# ============ API ROUTES ============

@app.route('/')
def dashboard():
    """Main investigation dashboard"""
    return render_template_string(DASHBOARD_HTML)


@app.route('/api/upload', methods=['POST'])
def upload_file():
    """Upload single file with metadata"""
    if 'file' not in request.files:
        return jsonify({'success': False, 'error': 'No file provided'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'success': False, 'error': 'Empty filename'}), 400

    if not allowed_file(file.filename):
        return jsonify({'success': False, 'error': 'File type not allowed'}), 400

    # Save file
    filename = secure_filename(file.filename)
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    saved_name = f"{timestamp}_{filename}"
    filepath = os.path.join(UPLOADS_DIR, saved_name)
    file.save(filepath)

    # Calculate hash
    file_hash = get_file_hash(filepath)
    file_size = os.path.getsize(filepath)

    # Get metadata
    category = request.form.get('category', '')
    description = request.form.get('description', '')
    auto_analyze = request.form.get('auto_analyze', 'false') == 'true'

    # Store in DB
    conn = sqlite3.connect(DB_PATH)
    c = conn.cursor()
    c.execute('''INSERT INTO uploads 
                 (filename, original_name, file_hash, size_bytes, category, description, auto_analyzed)
                 VALUES (?, ?, ?, ?, ?, ?, ?)''',
              (saved_name, filename, file_hash, file_size, category, description, auto_analyze))
    upload_id = c.lastrowid
    conn.commit()
    conn.close()

    result = {
        'success': True,
        'id': upload_id,
        'filename': saved_name,
        'size': file_size,
        'hash': file_hash,
        'message': f'Uploaded: {filename}'
    }

    if auto_analyze:
        analysis = analyze_uploaded_file(filepath, saved_name)
        result['analysis'] = analysis
        result['message'] += ' (analyzed)'

    return jsonify(result), 200


@app.route('/api/upload/batch', methods=['POST'])
def upload_batch():
    """Upload and extract ZIP archive"""
    if 'file' not in request.files:
        return jsonify({'success': False, 'error': 'No file provided'}), 400

    file = request.files['file']
    if not file.filename.endswith('.zip'):
        return jsonify({'success': False, 'error': 'Only ZIP files allowed'}), 400

    # Save ZIP
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    zip_name = f"{timestamp}_{secure_filename(file.filename)}"
    zip_path = os.path.join(UPLOADS_DIR, zip_name)
    file.save(zip_path)

    # Extract
    extract_dir = os.path.join(UPLOADS_DIR, f"{timestamp}_extracted")
    os.makedirs(extract_dir, exist_ok=True)

    extracted_files = []
    try:
        with zipfile.ZipFile(zip_path, 'r') as zip_ref:
            zip_ref.extractall(extract_dir)
            extracted_files = zip_ref.namelist()
    except Exception as e:
        return jsonify({'success': False, 'error': f'Extraction failed: {str(e)}'}), 500

    # Catalog extracted files
    source = request.form.get('source', 'Batch ZIP upload')
    conn = sqlite3.connect(DB_PATH)
    c = conn.cursor()

    cataloged = []
    for root, dirs, files in os.walk(extract_dir):
        for f in files:
            full_path = os.path.join(root, f)
            rel_path = os.path.relpath(full_path, UPLOADS_DIR)
            file_hash = get_file_hash(full_path)
            file_size = os.path.getsize(full_path)

            c.execute('''INSERT INTO uploads 
                         (filename, original_name, file_hash, size_bytes, source, status)
                         VALUES (?, ?, ?, ?, ?, ?)''',
                      (rel_path, f, file_hash, file_size, source, 'pending'))
            cataloged.append({'name': f, 'size': file_size})

    conn.commit()
    conn.close()

    return jsonify({
        'success': True,
        'message': f'Extracted {len(cataloged)} files from archive',
        'zip_file': zip_name,
