def analyze_uploaded_file(filepath, filename):
    """Analyze a file and return findings"""
    analysis = {
        'filename': filename,
        'file_type': filename.split('.')[-1] if '.' in filename else 'unknown',
        'size_bytes': os.path.getsize(filepath),
        'findings': [],
        'keywords_found': [],
        'risk_indicators': [],
        'recommendation': 'pending'
    }

    # Keywords to look for in various file types
    suspicious_keywords = [
        'private_key', 'secret', 'password', 'api_key', 'token',
        'backdoor', 'exploit', 'rug', 'scam', 'drain',
        '0x', 'wallet', 'transfer', 'withdraw'
    ]

    technical_keywords = [
        'def', 'class', 'import', 'function', 'contract',
        'database', 'api', 'endpoint', 'webhook'
    ]

    try:
        # Try to read as text
        with open(filepath, 'r', encoding='utf-8', errors='ignore') as f:
            content = f.read()[:100000]  # First 100KB

            # Check for keywords
            for kw in suspicious_keywords:
                if kw.lower() in content.lower():
                    analysis['keywords_found'].append(kw)

            for kw in technical_keywords:
                if kw.lower() in content.lower():
                    analysis['keywords_found'].append(kw)

            # File-type specific analysis
            if filename.endswith('.py'):
                analysis['findings'].append('Python source code detected')
                if 'flask' in content.lower() or 'fastapi' in content.lower():
                    analysis['findings'].append('Web framework usage detected')
                if 'telegram' in content.lower() or 'bot' in content.lower():
                    analysis['findings'].append('Telegram bot code detected')

            elif filename.endswith('.json'):
                try:
                    data = json.loads(content)
                    analysis['findings'].append(f'Valid JSON with {len(data)} top-level keys')
                except:
                    analysis['findings'].append('Invalid JSON format')

            elif filename.endswith('.env') or '.env' in filename:
                analysis['risk_indicators'].append('Environment file - may contain secrets')
                analysis['findings'].append('Configuration/secrets file')

            elif filename.endswith('.log'):
                lines = content.count('\n')
                analysis['findings'].append(f'Log file with ~{lines} lines')
                if 'error' in content.lower():
                    analysis['risk_indicators'].append('Errors found in logs')

            elif filename.endswith('.sql'):
                analysis['findings'].append('SQL database file')
                if 'password' in content.lower() or 'user' in content.lower():
                    analysis['findings'].append('May contain user data')
    except Exception as e:
        analysis['findings'].append(f'Could not analyze content: {str(e)}')

    # Determine recommendation
    if analysis['risk_indicators']:
        analysis['recommendation'] = 'review'
    elif len(analysis['keywords_found']) > 5:
        analysis['recommendation'] = 'useful'
    elif analysis['file_type'] in ['py', 'js', 'json', 'sql', 'env']:
        analysis['recommendation'] = 'useful'
    else:
        analysis['recommendation'] = 'review'

