    """Auto-categorize all pending files"""
    conn = sqlite3.connect(DB_PATH)
    c = conn.cursor()
    c.execute('SELECT id, filename FROM uploads WHERE status = "pending"')
    pending = c.fetchall()

    processed = 0
    for file_id, filename in pending:
        filepath = os.path.join(UPLOADS_DIR, filename)
        if os.path.exists(filepath):
            analysis = analyze_uploaded_file(filepath, filename)
            status = analysis.get('recommendation', 'review')
            if status == 'review':
                status = 'pending'  # Keep as pending for manual review
            c.execute('UPDATE uploads SET status = ?, analysis_result = ? WHERE id = ?',
                      (status, json.dumps(analysis), file_id))
            processed += 1

    conn.commit()
    conn.close()

    return jsonify({'success': True, 'processed': processed})


