    evidence_items = [dict(row) for row in c.fetchall()]

    c.execute('SELECT * FROM investigation_notes')
    notes = [dict(row) for row in c.fetchall()]

    c.execute('SELECT * FROM summary WHERE id = 1')
    summary_row = c.fetchone()
    conn.close()

    # Generate report
    report_time = datetime.now().strftime('%Y-%m-%d_%H%M%S')
    report_path = f'{INVESTIGATION_DIR}/report_{report_time}.md'

    report_content = f"""# Rug Muncher Investigation Report
Generated: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}

## Summary Statistics
- Total Files Uploaded: {len(uploads)}
- Evidence Items: {len(evidence_items)}
- Investigation Notes: {len(notes)}

## File Breakdown
"""

    status_counts = {}
    for u in uploads:
        status = u.get('status', 'unknown')
        status_counts[status] = status_counts.get(status, 0) + 1

    for status, count in status_counts.items():
        report_content += f"- {status.capitalize()}: {count}\n"

    if summary_row:
        report_content += f"""
## Backend Architecture Summary
{summary_row[1] or 'No summary provided'}

## Key Findings
{summary_row[2] or 'No findings recorded'}

## Recommendations
{summary_row[3] or 'No recommendations recorded'}
"""

    report_content += """
## Useful Files (Backend Relevant)
"""
    useful_files = [u for u in uploads if u.get('status') == 'useful']
    for f in useful_files[:50]:  # Limit to first 50
        report_content += f"- `{f['filename']}` - {f.get('description', 'No description')}\n"

    report_content += """
## Suspicious Files
"""
    suspicious_files = [u for u in uploads if u.get('status') == 'suspicious']
    for f in suspicious_files:
        report_content += f"- `{f['filename']}` - {f.get('description', 'No description')}\n"

    report_content += """
## Evidence Items
"""
    for e in evidence_items:
        report_content += f"""### {e.get('evidence_type', 'Unknown').upper()} - {e.get('severity', 'unknown')}
{e.get('description', 'No description')}

"""

    with open(report_path, 'w') as f:
        f.write(report_content)

    return jsonify({'success': True, 'report_path': report_path})


