"""
🔍 RUG MUNCHER INVESTIGATION BACKEND
=====================================
Production-ready backend for scam investigation
- Supabase integration for auto database building
- n8n webhook support
- Secure file handling
- No hardcoded secrets

Environment Variables Required:
- SUPABASE_URL
- SUPABASE_KEY
- N8N_WEBHOOK_URL (optional)
- ADMIN_API_KEY (for protected endpoints)
"""

from flask import Flask, request, jsonify, render_template_string, send_from_directory
from flask_cors import CORS
from werkzeug.utils import secure_filename
from functools import wraps
import os
import json
import hashlib
import zipfile
import asyncio
import aiohttp
from datetime import datetime
from typing import Dict, List, Optional, Any

app = Flask(__name__)
CORS(app, origins=["*"])  # Configure for your domain in production

# ═══════════════════════════════════════════════════════════
# CONFIGURATION - NO HARDCODED SECRETS
# ═══════════════════════════════════════════════════════════

class Config:
    """All config from environment variables only"""
    SUPABASE_URL = os.getenv('SUPABASE_URL')
    SUPABASE_KEY = os.getenv('SUPABASE_KEY')
    SUPABASE_SERVICE_KEY = os.getenv('SUPABASE_SERVICE_KEY')
    N8N_WEBHOOK_URL = os.getenv('N8N_WEBHOOK_URL')
    ADMIN_API_KEY = os.getenv('ADMIN_API_KEY')

    # Directories
    BASE_DIR = '/root/investigation'
    UPLOADS_DIR = os.path.join(BASE_DIR, 'uploads')
    EVIDENCE_DIR = os.path.join(BASE_DIR, 'evidence')
    CATEGORIZED_DIR = os.path.join(BASE_DIR, 'categorized')

    # Allowed file types
    ALLOWED_EXTENSIONS = {
        'zip', 'pdf', 'txt', 'doc', 'docx', 'png', 'jpg', 'jpeg', 'gif',
        'mp4', 'json', 'csv', 'xls', 'xlsx', 'py', 'js', 'html', 'md',
        'log', 'sql', 'env', 'conf', 'config', 'yaml', 'yml', 'xml'
    }

    MAX_FILE_SIZE = 100 * 1024 * 1024  # 100MB

# Create directories
for d in [Config.UPLOADS_DIR, Config.EVIDENCE_DIR, Config.CATEGORIZED_DIR,
          os.path.join(Config.CATEGORIZED_DIR, 'critical'),
          os.path.join(Config.CATEGORIZED_DIR, 'useful'),
          os.path.join(Config.CATEGORIZED_DIR, 'suspicious'),
          os.path.join(Config.CATEGORIZED_DIR, 'useless')]:
    os.makedirs(d, exist_ok=True)

# ═══════════════════════════════════════════════════════════
# SUPABASE CLIENT
# ═══════════════════════════════════════════════════════════

class SupabaseClient:
    """Simple Supabase REST client"""

    def __init__(self):
        self.url = Config.SUPABASE_URL
        self.key = Config.SUPABASE_SERVICE_KEY or Config.SUPABASE_KEY
        self.headers = {
            'apikey': self.key,
            'Authorization': f'Bearer {self.key}',
            'Content-Type': 'application/json'
        } if self.key else None

    async def insert(self, table: str, data: Dict) -> Dict:
        """Insert data into Supabase table"""
        if not self.url or not self.key:
            return {'error': 'Supabase not configured'}

        url = f"{self.url}/rest/v1/{table}"

        async with aiohttp.ClientSession() as session:
            async with session.post(url, headers=self.headers, json=data) as resp:
                if resp.status in [200, 201]:
                    return {'success': True, 'data': await resp.json()}
                return {'error': f'Status {resp.status}', 'message': await resp.text()}

    async def select(self, table: str, limit: int = 100) -> List[Dict]:
        """Select data from Supabase"""
        if not self.url or not self.key:
            return []

        url = f"{self.url}/rest/v1/{table}?limit={limit}"

        async with aiohttp.ClientSession() as session:
            async with session.get(url, headers=self.headers) as resp:
                if resp.status == 200:
                    return await resp.json()
                return []

supabase = SupabaseClient()

# ═══════════════════════════════════════════════════════════
# N8N WEBHOOK HANDLER
# ═══════════════════════════════════════════════════════════

async def trigger_n8n(event_type: str, data: Dict):
    """Trigger n8n workflow via webhook"""
    if not Config.N8N_WEBHOOK_URL:
        return

    payload = {
        'event': event_type,
        'timestamp': datetime.now().isoformat(),
        'data': data
    }

    try:
        async with aiohttp.ClientSession() as session:
            async with session.post(Config.N8N_WEBHOOK_URL, json=payload, timeout=10) as resp:
                return resp.status == 200
    except Exception as e:
        print(f"n8n webhook failed: {e}")
        return False

# ═══════════════════════════════════════════════════════════
# AUTH DECORATORS
# ═══════════════════════════════════════════════════════════

def require_api_key(f):
    """Decorator to require API key for protected endpoints"""
    @wraps(f)
    def decorated(*args, **kwargs):
        if not Config.ADMIN_API_KEY:
            return jsonify({'error': 'API key not configured'}), 500

        api_key = request.headers.get('X-API-Key') or request.args.get('api_key')
        if not api_key or api_key != Config.ADMIN_API_KEY:
            return jsonify({'error': 'Unauthorized'}), 401

        return f(*args, **kwargs)
    return decorated

# ═══════════════════════════════════════════════════════════
# FILE UTILITIES
# ═══════════════════════════════════════════════════════════

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in Config.ALLOWED_EXTENSIONS

def get_file_hash(filepath):
    hash_md5 = hashlib.md5()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(4096), b""):
            hash_md5.update(chunk)
    return hash_md5.hexdigest()

def analyze_file_content(filepath: str, filename: str) -> Dict:
    """Analyze file content for investigation purposes"""
    analysis = {
        'filename': filename,
        'file_type': filename.split('.')[-1] if '.' in filename else 'unknown',
        'size_bytes': os.path.getsize(filepath),
        'keywords_found': [],
        'risk_indicators': [],
        'recommendation': 'review'
    }

    # Suspicious keywords to look for
    suspicious_keywords = [
        'private_key', 'secret', 'password', 'api_key', 'token',
        'backdoor', 'exploit', 'rug', 'scam', 'drain', 'hack',
        '0x742d35Cc',  # The compromised address pattern
        'wallet', 'transfer', 'withdraw'
    ]

    try:
        with open(filepath, 'r', encoding='utf-8', errors='ignore') as f:
            content = f.read(100000)  # First 100KB

            for kw in suspicious_keywords:
                if kw.lower() in content.lower():
                    analysis['keywords_found'].append(kw)

            # File-type specific analysis
            if filename.endswith('.py'):
                analysis['file_type'] = 'python'
                if 'def ' in content:
                    analysis['functions'] = content.count('def ')

            elif filename.endswith('.json'):
                try:
                    data = json.loads(content)
                    analysis['json_keys'] = len(data) if isinstance(data, dict) else 0
                except:
                    analysis['risk_indicators'].append('Invalid JSON')

            elif filename.endswith('.env'):
                analysis['risk_indicators'].append('Environment file - check for secrets')
                analysis['recommendation'] = 'critical'

            elif filename.endswith('.log'):
                errors = content.lower().count('error')
                if errors > 10:
                    analysis['risk_indicators'].append(f'Multiple errors ({errors})')
    except Exception as e:
        analysis['read_error'] = str(e)

    # Auto-categorize based on findings
    if '0x742d35Cc' in str(analysis['keywords_found']):
        analysis['recommendation'] = 'critical'
        analysis['risk_indicators'].append('HARDCODED WALLET ADDRESS DETECTED')
    elif analysis['risk_indicators']:
        analysis['recommendation'] = 'suspicious'
    elif len(analysis['keywords_found']) > 5:
        analysis['recommendation'] = 'useful'

    return analysis

