@app.route('/api/upload', methods=['POST'])
def upload_file():
    """
    Upload single file with metadata

    Form fields:
    - file: The file to upload
    - category: logs, financial, communication, code, config, evidence, etc.
    - source: Where did this come from?
    - description: What is this file?
    - case_id: Investigation case ID
    """
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']
    if file.filename == '' or not allowed_file(file.filename):
        return jsonify({'error': 'Invalid file'}), 400

    # Check file size
    file.seek(0, os.SEEK_END)
    file_size = file.tell()
    file.seek(0)

    if file_size > Config.MAX_FILE_SIZE:
        return jsonify({'error': f'File too large (max {Config.MAX_FILE_SIZE/1024/1024}MB)'}), 400

    # Metadata
    category = request.form.get('category', 'uncategorized')
    source = request.form.get('source', 'unknown')
    description = request.form.get('description', '')
    case_id = request.form.get('case_id', 'default')

    # Save file
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    safe_name = secure_filename(file.filename)
    saved_name = f"{case_id}_{timestamp}_{safe_name}"
    filepath = os.path.join(Config.UPLOADS_DIR, saved_name)
    file.save(filepath)

    # Calculate hash
    file_hash = get_file_hash(filepath)

    # Analyze content
    analysis = analyze_file_content(filepath, safe_name)

    # Prepare record
    record = {
        'filename': saved_name,
        'original_name': safe_name,
        'file_hash': file_hash,
        'size_bytes': file_size,
        'category': category,
        'source': source,
        'description': description,
        'case_id': case_id,
        'analysis': json.dumps(analysis),
        'status': analysis.get('recommendation', 'pending'),
        'uploaded_at': datetime.now().isoformat(),
        'path': filepath
    }

    # Save to Supabase if configured
    if Config.SUPABASE_URL:
        asyncio.run(supabase.insert('investigation_files', record))

    # Trigger n8n webhook
    asyncio.run(trigger_n8n('file_uploaded', record))

    return jsonify({
        'success': True,
        'file_id': file_hash[:16],
        'filename': saved_name,
        'analysis': analysis,
        'message': f'File uploaded and analyzed'
    })

@app.route('/api/upload/batch', methods=['POST'])
def upload_batch():
    """Upload and extract ZIP archive"""
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']
    if not file.filename.endswith('.zip'):
        return jsonify({'error': 'Only ZIP files allowed'}), 400

    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    case_id = request.form.get('case_id', 'default')
    batch_name = request.form.get('batch_name', 'unnamed')
    source = request.form.get('source', 'batch_upload')

    # Save ZIP
    zip_name = f"{case_id}_{timestamp}_{secure_filename(file.filename)}"
    zip_path = os.path.join(Config.UPLOADS_DIR, zip_name)
    file.save(zip_path)

    # Extract
    extract_dir = os.path.join(Config.UPLOADS_DIR, f"{case_id}_{timestamp}_extracted")
    os.makedirs(extract_dir, exist_ok=True)

    try:
        with zipfile.ZipFile(zip_path, 'r') as zip_ref:
            zip_ref.extractall(extract_dir)
            extracted_files = zip_ref.namelist()
    except Exception as e:
        return jsonify({'error': f'Extraction failed: {str(e)}'}), 500

    # Catalog extracted files
    cataloged = []
    for root, dirs, files in os.walk(extract_dir):
        for f in files:
            full_path = os.path.join(root, f)
            rel_path = os.path.relpath(full_path, Config.UPLOADS_DIR)

            record = {
                'filename': rel_path,
                'original_name': f,
                'file_hash': get_file_hash(full_path),
                'size_bytes': os.path.getsize(full_path),
                'category': 'batch_extracted',
                'batch_name': batch_name,
                'source': source,
                'case_id': case_id,
                'uploaded_at': datetime.now().isoformat(),
                'status': 'pending'
            }

            if Config.SUPABASE_URL:
                asyncio.run(supabase.insert('investigation_files', record))

            cataloged.append(record)

    # Trigger n8n
    asyncio.run(trigger_n8n('batch_uploaded', {
        'batch_name': batch_name,
        'files_count': len(cataloged),
        'case_id': case_id
    }))

    return jsonify({
        'success': True,
        'batch_name': batch_name,
        'files_uploaded': len(cataloged),
        'extracted_to': extract_dir
    })

