@app.route('/api/files', methods=['GET'])
def list_files():
    """List files from Supabase or local manifest"""
    case_id = request.args.get('case_id')
    status = request.args.get('status')
    category = request.args.get('category')

    if Config.SUPABASE_URL:
        # Query from Supabase
        filters = []
        if case_id:
            filters.append(f'case_id=eq.{case_id}')
        if status:
            filters.append(f'status=eq.{status}')
        if category:
            filters.append(f'category=eq.{category}')

        # Return query info for now
        return jsonify({
            'source': 'supabase',
            'filters': {
                'case_id': case_id,
                'status': status,
                'category': category
            },
            'message': 'Query Supabase directly or use local manifest'
        })
    else:
        # Local manifest fallback
        manifest_path = os.path.join(Config.BASE_DIR, 'manifest.json')
        if os.path.exists(manifest_path):
            with open(manifest_path, 'r') as f:
                manifest = json.load(f)
            return jsonify({
                'source': 'local',
                'files': manifest.get('files', []),
                'count': len(manifest.get('files', []))
            })

        return jsonify({'files': [], 'count': 0})

